@startuml
participant "User" as User1
participant "WebApp" as WebApp1
participant "DB" as DB1

participant "User" as User2
participant "WebApp" as WebApp2
participant "DB" as DB2

User1 ..> WebApp1 : [POST] / driver {body}
WebApp1 ..> DB1 : save driver
DB1 ..> WebApp1 : OK
WebApp1 ..> User1 : 201 CREATED {body}

User2 ..> WebApp2 : [GET] / driver
WebApp2 ..> DB2 : get driver
DB2 ..> WebApp2 : driver object
WebApp2 ..> User2 : 200 OK {body}

@enduml
